// Query upcoming non-cancelled bookings in the next 14 days.
// Buffer-aware conflict detection: any two bookings for the same
// advisor whose [start, end+buffer) intervals overlap.
const windowDays   = parseInt($env.CLX_CONFLICT_WINDOW_DAYS  || '14', 10);
const bufferMins   = parseInt($env.CLX_CONFLICT_BUFFER_MINS  || '15',  10);
const nowIso       = new Date().toISOString();
const untilIso     = new Date(Date.now() + windowDays * 86400000).toISOString();
const qs = [
  'select=id,lead_id,client_id,advisor_id,scheduled_at,duration_minutes,status,provider,meeting_link,notes',
  'status=in.(scheduled,confirmed)',
  'scheduled_at=gte.' + encodeURIComponent(nowIso),
  'scheduled_at=lte.' + encodeURIComponent(untilIso),
  'order=advisor_id.asc,scheduled_at.asc',
  'limit=500'
].join('&');
return { json: { qs: qs, window_days: windowDays, buffer_mins: bufferMins, now_iso: nowIso } };

// Detect overlaps. Algorithm:
//   1. Group bookings by advisor_id (null grouped together as 'unassigned').
//   2. Within each group, sweep sorted-by-scheduled_at and compare each
//      booking's [start, end + buffer) against the next bookings until
//      one starts after this one ends — O(n*k) where k = local overlap
//      depth (small in practice).
// Each conflict produces a sentinel_alerts row with aggregation_key
// containing both booking IDs sorted, so the same conflict pair only
// alerts once per day.
const allOf = function (name) {
  try {
    const items = $(name).all().map(function (i) { return i.json; });
    if (items.length === 1 && Array.isArray(items[0])) return items[0];
    if (items.length === 1 && items[0] && typeof items[0] === 'object' && !Array.isArray(items[0]) && items[0].id) return [items[0]];
    return items.filter(function (x) { return x && x.id; });
  } catch (e) { return []; }
};

const bookings = allOf('Query Bookings');
const meta     = $('Build Query').first().json;
const bufferMs = (meta.buffer_mins || 0) * 60000;
const todayKey = new Date().toISOString().slice(0, 10);

if (bookings.length < 2) {
  return [{ json: { _no_conflicts: true, bookings_examined: bookings.length, window_days: meta.window_days, buffer_mins: meta.buffer_mins } }];
}

const byAdvisor = {};
bookings.forEach(function (b) {
  const k = b.advisor_id || 'unassigned';
  if (!byAdvisor[k]) byAdvisor[k] = [];
  byAdvisor[k].push(b);
});

const conflicts = [];

Object.keys(byAdvisor).forEach(function (advisorId) {
  const list = byAdvisor[advisorId].slice().sort(function (a, b) {
    return new Date(a.scheduled_at).getTime() - new Date(b.scheduled_at).getTime();
  });
  for (let i = 0; i < list.length; i++) {
    const a = list[i];
    const aStart = new Date(a.scheduled_at).getTime();
    const aEnd   = aStart + (a.duration_minutes || 30) * 60000;
    const aEndWithBuffer = aEnd + bufferMs;
    for (let j = i + 1; j < list.length; j++) {
      const b = list[j];
      const bStart = new Date(b.scheduled_at).getTime();
      if (bStart >= aEndWithBuffer) break;  // sorted: no further overlaps possible
      const isOverlap   = bStart < aEnd;
      const isTightGap  = !isOverlap && bStart < aEndWithBuffer;
      conflicts.push({
        advisor_id:    advisorId === 'unassigned' ? null : advisorId,
        booking_a:     a,
        booking_b:     b,
        conflict_kind: isOverlap ? 'overlap' : 'tight_gap',
        gap_minutes:   Math.round((bStart - aEnd) / 60000)
      });
    }
  }
});

if (conflicts.length === 0) {
  return [{ json: { _no_conflicts: true, bookings_examined: bookings.length, window_days: meta.window_days, buffer_mins: meta.buffer_mins } }];
}

const now = new Date().toISOString();

return conflicts.map(function (c) {
  const idPair = [c.booking_a.id, c.booking_b.id].sort();
  const aggKey = 'conflict-' + idPair[0] + '-' + idPair[1] + '-' + todayKey;
  const severity = c.conflict_kind === 'overlap' ? 'critical' : 'warning';
  const aTime = new Date(c.booking_a.scheduled_at).toISOString();
  const bTime = new Date(c.booking_b.scheduled_at).toISOString();
  const title = (c.conflict_kind === 'overlap' ? '⚠️ Booking overlap' : '⏱️ Tight gap') +
    ' — ' + aTime.slice(0, 16) + ' vs ' + bTime.slice(0, 16);
  const message = c.conflict_kind === 'overlap'
    ? 'Two bookings overlap for advisor ' + (c.advisor_id || 'unassigned') + '. Buffer = ' + meta.buffer_mins + ' min.'
    : 'Only ' + c.gap_minutes + ' min between bookings (buffer = ' + meta.buffer_mins + ' min) for advisor ' + (c.advisor_id || 'unassigned') + '.';

  return {
    json: {
      module_name:     'ciro',
      alert_type:      'calendar_conflict',
      severity:        severity,
      title:           title.slice(0, 200),
      message:         message.slice(0, 500),
      details: {
        advisor_id:     c.advisor_id,
        conflict_kind:  c.conflict_kind,
        gap_minutes:    c.gap_minutes,
        buffer_minutes: meta.buffer_mins,
        booking_a: {
          id: c.booking_a.id, lead_id: c.booking_a.lead_id, client_id: c.booking_a.client_id,
          scheduled_at: c.booking_a.scheduled_at, duration_minutes: c.booking_a.duration_minutes,
          provider: c.booking_a.provider, meeting_link: c.booking_a.meeting_link, status: c.booking_a.status
        },
        booking_b: {
          id: c.booking_b.id, lead_id: c.booking_b.lead_id, client_id: c.booking_b.client_id,
          scheduled_at: c.booking_b.scheduled_at, duration_minutes: c.booking_b.duration_minutes,
          provider: c.booking_b.provider, meeting_link: c.booking_b.meeting_link, status: c.booking_b.status
        }
      },
      aggregation_key: aggKey,
      triggered_at:    now,
      status:          'open'
    }
  };
});
